import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { Form, Button, Alert, Card, Tabs, Tab } from 'react-bootstrap';
import '../Css/CreateProblem.css';

const defaultFormData = {
  title: '',
  category: 'algebra',
  difficulty: 'easy',
  description: '',
  imageUrl: '',
  solution: ''
};

const CreateProblem = () => {
  const [tabKey, setTabKey] = useState('normal');
  const [formData, setFormData] = useState({ ...defaultFormData });
  const [dailyFormData, setDailyFormData] = useState({ ...defaultFormData });
  const [message, setMessage] = useState({ text: '', variant: '' });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e, isDaily = false) => {
    const { name, value } = e.target;
    if (isDaily) {
      setDailyFormData(prev => ({ ...prev, [name]: value }));
    } else {
      setFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleSubmit = async (e, isDaily = false) => {
    e.preventDefault();
    setLoading(true);

    const data = isDaily ? dailyFormData : formData;

    try {
      const token = localStorage.getItem('token');

      const url = isDaily
        ? 'http://localhost:5000/api/daily-challenge'
        : 'http://localhost:5000/api/problems';

      const response = await axios.post(url, data, {
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        timeout: 5000
      });

      setMessage({ text: `Problem created successfully!`, variant: 'success' });

      if (isDaily) {
        setDailyFormData({ ...defaultFormData });
      } else {
        setFormData({ ...defaultFormData });
        setTimeout(() => navigate(`/problems/${response.data._id}`), 2000);
      }

    } catch (error) {
      setMessage({
        text: error.response?.data?.message || error.message || 'Network error',
        variant: 'danger'
      });
    } finally {
      setLoading(false);
    }
  };

  const renderForm = (isDaily = false) => {
    const data = isDaily ? dailyFormData : formData;
    return (
      <Form onSubmit={(e) => handleSubmit(e, isDaily)}>
        <Form.Group className="mb-3">
          <Form.Label>Title</Form.Label>
          <Form.Control
            type="text"
            name="title"
            value={data.title}
            onChange={(e) => handleChange(e, isDaily)}
            required
          />
        </Form.Group>

        <Form.Group className="mb-3">
          <Form.Label>Category</Form.Label>
          <Form.Select
            name="category"
            value={data.category}
            onChange={(e) => handleChange(e, isDaily)}
            required
          >
            <option value="algebra">Algebra</option>
            <option value="geometry">Geometry</option>
            <option value="calculus">Calculus</option>
            <option value="trigonometry">Trigonometry</option>
          </Form.Select>
        </Form.Group>

        <Form.Group className="mb-3">
          <Form.Label>Difficulty</Form.Label>
          <Form.Select
            name="difficulty"
            value={data.difficulty}
            onChange={(e) => handleChange(e, isDaily)}
            required
          >
            <option value="easy">Easy</option>
            <option value="medium">Medium</option>
            <option value="hard">Hard</option>
          </Form.Select>
        </Form.Group>

        <Form.Group className="mb-3">
          <Form.Label>Description</Form.Label>
          <Form.Control
            as="textarea"
            name="description"
            rows={5}
            value={data.description}
            onChange={(e) => handleChange(e, isDaily)}
            required
          />
        </Form.Group>

        <Form.Group className="mb-3">
          <Form.Label>Image URL (optional)</Form.Label>
          <Form.Control
            type="url"
            name="imageUrl"
            value={data.imageUrl}
            onChange={(e) => handleChange(e, isDaily)}
            placeholder="https://example.com/image.png"
          />
        </Form.Group>

        <Form.Group className="mb-3">
          <Form.Label>Solution</Form.Label>
          <Form.Control
            as="textarea"
            name="solution"
            rows={4}
            value={data.solution}
            onChange={(e) => handleChange(e, isDaily)}
            required
          />
        </Form.Group>

        <Button type="submit" disabled={loading} className="submit-btn">
          {loading ? 'Submitting...' : isDaily ? 'Create Daily Challenge' : 'Create Problem'}
        </Button>
      </Form>
    );
  };

  return (
    <div className="problem-list-page">
      <div className="problem-list-container">
        <Card className="create-problem-card">
          <h2 className="mb-4">Problem Creator</h2>
          {message.text && (
            <Alert
              variant={message.variant}
              onClose={() => setMessage({ text: '', variant: '' })}
              dismissible
            >
              {message.text}
            </Alert>
          )}

          <Tabs activeKey={tabKey} onSelect={(k) => setTabKey(k)} className="mb-3">
            <Tab eventKey="normal" title="Create Problem">
              {renderForm(false)}
            </Tab>
            <Tab eventKey="daily" title="Create Daily Challenge">
              {renderForm(true)}
            </Tab>
          </Tabs>
        </Card>
      </div>
    </div>
  );
};

export default CreateProblem;
